// src/pages/Menu.jsx
import React, { useEffect, useState } from "react";
import api from "../api/axios";
import Navbar from "../components/Navbar/Navbar";
import Footer from "../components/Footer/Footer";

export default function Menu() {
  const [menuData, setMenuData] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [openItemId, setOpenItemId] = useState(null);
  const [hoveredItem, setHoveredItem] = useState(null);
  const [searchTerm, setSearchTerm] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");
  const [feedback, setFeedback] = useState("");
  const [feedbackSubmitted, setFeedbackSubmitted] = useState(false);
  const [showScrollTop, setShowScrollTop] = useState(false);
  const [userRole, setUserRole] = useState("customer");

  // Body padding (page specific)
  useEffect(() => {
    const style = document.createElement("style");
    style.innerHTML = `body { padding-top: 80px; }`;
    document.head.appendChild(style);
    return () => document.head.removeChild(style);
  }, []);

  // Get user role
  useEffect(() => {
    const role = localStorage.getItem("userRole") || "customer";
    setUserRole(role);
  }, []);

  // Fetch menu
  useEffect(() => {
    const fetchMenu = async () => {
      try {
        const res = await api.get("/items");
        const grouped = res.data.reduce((acc, item) => {
          const cat = item.category || "Uncategorized";
          if (!acc[cat]) acc[cat] = [];
          acc[cat].push({
            ...item,
            rating: (Math.random() * 2 + 3).toFixed(1),
            popular: Math.random() > 0.7,
          });
          return acc;
        }, {});

        const final = Object.keys(grouped).map((c, i) => ({
          category: { category_id: i, category_name: c },
          items: grouped[c],
        }));

        setMenuData(final);
        setLoading(false);
      } catch (err) {
        console.error(err);
        setError("Failed to load menu items.");
        setLoading(false);
      }
    };
    fetchMenu();
  }, []);

  const toggleDescription = (id) =>
    setOpenItemId(openItemId === id ? null : id);

  const handleFeedbackSubmit = () => {
    if (!feedback.trim()) return alert("Please write some feedback.");

    const entry = {
      id: Date.now(),
      name: localStorage.getItem("currentUser") || "Anonymous",
      comment: feedback.trim(),
      date: new Date().toISOString(),
    };

    const stored = JSON.parse(localStorage.getItem("feedbackList")) || [];
    localStorage.setItem("feedbackList", JSON.stringify([entry, ...stored]));

    setFeedback("");
    setFeedbackSubmitted(true);
    setTimeout(() => setFeedbackSubmitted(false), 3000);
  };

  // Filtered menu
  const filteredMenu = menuData
    .map((section) => ({
      ...section,
      items: section.items.filter(
        (i) =>
          i.item_name.toLowerCase().includes(searchTerm.toLowerCase()) &&
          (selectedCategory === "All" ||
            section.category.category_name === selectedCategory)
      ),
    }))
    .filter((s) => s.items.length > 0);

  const categories = ["All", ...menuData.map((s) => s.category.category_name)];

  const getRandomDescription = (name) => {
    const arr = [
      `Delicious ${name} made fresh daily.`,
      `A tasty choice — ${name} will delight you.`,
      `Prepared with the finest ingredients.`,
      `Our special ${name}, loved by all.`,
    ];
    return arr[Math.floor(Math.random() * arr.length)];
  };

  useEffect(() => {
    const onScroll = () => setShowScrollTop(window.scrollY > 300);
    window.addEventListener("scroll", onScroll);
    return () => window.removeEventListener("scroll", onScroll);
  }, []);

  return (
    <div style={{ background: "#fff5e6", minHeight: "100vh" }}>
      <Navbar />

      <div
        style={{
          display: "flex",
          gap: "35px",
          padding: "30px",
          alignItems: "flex-start",
        }}
      >
        {/* LEFT SIDE */}
        <div style={{ flex: 2 }}>
          <h1>🍽️ Our Menu</h1>

          {/* Search + Filter */}
          <div
            style={{
              marginBottom: 20,
              display: "flex",
              gap: 12,
              flexWrap: "wrap",
            }}
          >
            <input
              placeholder="Search items..."
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
              style={{
                padding: 10,
                borderRadius: 6,
                border: "1px solid #ccc",
                flex: 1,
              }}
            />

            <select
              value={selectedCategory}
              onChange={(e) => setSelectedCategory(e.target.value)}
              style={{
                padding: 10,
                borderRadius: 6,
                border: "1px solid #ccc",
              }}
            >
              {categories.map((c) => (
                <option key={c}>{c}</option>
              ))}
            </select>
          </div>

          {loading && <p>⏳ Loading...</p>}
          {error && <p style={{ color: "red" }}>{error}</p>}

          {/* MENU SECTIONS */}
          {filteredMenu.map((section) => (
            <div key={section.category.category_id} style={{ marginBottom: 35 }}>
              <h2>{section.category.category_name}</h2>

              <div
                style={{
                  display: "flex",
                  flexWrap: "wrap",
                  gap: "20px",
                  marginTop: "15px",
                }}
              >
                {section.items.map((item) => (
                  <div key={item.item_id} style={{ flex: "1 1 220px" }}>
                    <button
                      onMouseEnter={() => setHoveredItem(item.item_id)}
                      onMouseLeave={() => setHoveredItem(null)}
                      onClick={() => toggleDescription(item.item_id)}
                      style={{
                        width: "100%",
                        padding: "15px",
                        borderRadius: 10,
                        border: "1px solid #333",
                        background:
                          hoveredItem === item.item_id ? "#fff2d9" : "#fff8f0",
                        boxShadow:
                          hoveredItem === item.item_id
                            ? "0px 2px 8px rgba(0,0,0,0.2)"
                            : "none",
                        transition: "0.25s",
                        cursor: "pointer",
                        fontWeight: "bold",
                      }}
                    >
                      {item.item_name} – ${parseFloat(item.price).toFixed(2)}
                      <span
                        style={{
                          float: "right",
                          fontSize: "0.85em",
                          color: "#b87b1c",
                        }}
                      >
                        {item.popular && "🔥 "}⭐{item.rating}
                      </span>
                    </button>

                    {openItemId === item.item_id && (
                      <p style={{ marginTop: 8, fontStyle: "italic" }}>
                        {getRandomDescription(item.item_name)}
                      </p>
                    )}
                  </div>
                ))}
              </div>
            </div>
          ))}

          {/* FEEDBACK */}
          {userRole === "customer" && (
            <div
              style={{
                marginTop: 30,
                padding: 20,
                background: "#fff4e0",
                borderRadius: 10,
              }}
            >
              <h3 style={{ color: "#b87b1c" }}>💬 Share Feedback</h3>
              <textarea
                value={feedback}
                onChange={(e) => setFeedback(e.target.value)}
                placeholder="Write something..."
                rows={4}
                style={{
                  width: "100%",
                  padding: 10,
                  borderRadius: 6,
                  border: "1px solid #ccc",
                  marginTop: 10,
                }}
              />
              <button
                onClick={handleFeedbackSubmit}
                style={{
                  marginTop: 10,
                  padding: 12,
                  width: "100%",
                  background: "#d35400",
                  color: "white",
                  border: "none",
                  borderRadius: 6,
                  cursor: "pointer",
                  fontWeight: "bold",
                }}
              >
                Submit
              </button>

              {feedbackSubmitted && (
                <p style={{ marginTop: 10, color: "green" }}>
                  ✅ Feedback sent!
                </p>
              )}
            </div>
          )}
        </div>

        {/* RIGHT SIDE IMAGES */}
        <div
          style={{
            flex: 1,
            display: "flex",
            flexDirection: "column",
            gap: "15px",
          }}
        >
          <img src="/Images/Salads.jpeg" style={imgStyle} />
          <img src="/Images/Beverages1.jpeg" style={imgStyle} />
          <img src="/Images/ShrimpsPlatter.jpeg" style={imgStyle} />
          <img src="/Images/BurgerMain.jpeg" style={imgStyle} />
        </div>
      </div>

      {showScrollTop && (
        <button
          onClick={() => window.scrollTo({ top: 0, behavior: "smooth" })}
          style={{
            position: "fixed",
            right: 20,
            bottom: 30,
            width: 45,
            height: 45,
            borderRadius: "50%",
            background: "#d35400",
            color: "#fff",
            border: "none",
            fontSize: 22,
            cursor: "pointer",
          }}
        >
          ↑
        </button>
      )}

      <Footer />
    </div>
  );
}

const imgStyle = {
  width: "100%",
  borderRadius: 10,
};
